  "create_guest_url": null,
  "login_by_guest_url": null,
  "get_account_url": "https://brain.dopple.ai/get_user_details?username={username}",
  "create_session_url": "https://dopple-be-232946234386.us-central1.run.app/api/engagements",
  "get_chat_setting_url": "https://brain.dopple.ai/get_user_details?username={username}",
